import kaplay from "kaplay";

const k = kaplay();

k.loadRoot("./");

k.loadSprite("knife", "/sprites/KNIFE.png");
k.loadSprite("blood", "/sprites/BLOOD.png");
k.loadSprite("sacrifice", "/sprites/SACRIFICE.png");
k.loadSprite("dance", "/sprites/COW_DANCE.png", {
    sliceX: 2,
    sliceY: 2,
    anims: {
        dance: { from: 0, to: 3, loop: true }
    }
});

k.loadSound("moo", "/sounds/MOO.mp3");
k.loadSound("oof", "/sounds/OOF.mp3");

k.setCursor("none");

function spawnCow() {
    return k.add([
        k.sprite("dance"),
        k.pos(100, 100),
        k.scale(4),
        k.area(),
        k.health(2),
        "cow"
    ]);
}

const score = k.add([
    k.text(""),
    k.pos(24, 24),
    { value: 0 },
    k.color(255, 0, 0)
]);

score.text = "Katliam: " + score.value ;

const name = k.add([
    k.text("by MetaMsa"),
    k.pos(24, 550),
    { value: 0 },
    color(255, 0, 0),
]);

const cursor = k.add([
    k.sprite("knife"),
    k.pos(),
    k.fakeMouse({
        followMouse: true,
    }),
    k.scale(2),
    k.z(30)
]);

k.onKeyPress("f", () => cursor.press());
k.onKeyRelease("f", () => cursor.release());

k.onTouchStart((pos) => cursor.moveTo(pos.x, pos.y));

let vx = 200;
let vy = 200;

let cow = spawnCow();
cow.play("dance");

k.onClick("cow", (cow) => {
    if (cow.paused) return;

    if (cow.hp > 0) {
        cow.hp--;

        k.add([
            k.sprite("blood"),
            k.follow(cow, (100, 100)),
            k.pos(cursor.pos)
        ]);

        k.play("oof");

        vx += 50;
        vy += 50;
    } else {
        cow.paused = true;
        cow.use(k.sprite("sacrifice"));
        k.play("oof");
        score.value++;
        score.text = "Katliam: " + score.value;
        cow = spawnCow();
        cow.play("dance");
    }
});

k.onHover("cow", (cow) => {
    if (cow.paused) return;
    cursor.scaleTo(4);
});

k.onHoverEnd("cow", () => {
    cursor.scaleTo(2);
});

k.setBackground("cyan");

k.loop(10, () => {
    k.play("moo", { volume: 0.5 });
});

k.onUpdate("cow", (cow) => {
    cow.move(vx, vy);

    if (cow.pos.x <= 0 || cow.pos.x >= k.width() - cow.width) {
        vx *= -1;
    }

    if (cow.pos.y <= 0 || cow.pos.y >= k.height() - cow.height) {
        vy *= -1;
    }
});